DarkRPUI=DarkRPUI or {}; DarkRPUI.F4=DarkRPUI.F4 or {}
function DarkRPUI.F4.ShowJobDetail(job) local f=DarkRPUI.UI.CreateFrame(DarkRPUI.F4.ItemName(job),520,620); local mdl=DarkRPUI.UI.ModelPreview(f,job.model or job.models or "models/player/kleiner.mdl",true); mdl:SetPos(28,84); mdl:SetSize(464,330); DarkRPUI.UI.Text(job.description or "Review job requirements and loadout.","DarkRPUI.Small",32,430,DarkRPUI.Color("subtext")); local b=DarkRPUI.UI.PrimaryButton(f,"Become Job",function() DarkRPUI.F4.RunCommand(job.command or job.cmd); f:Remove() end); b:SetPos(32,540); b:SetSize(456,46) end
